import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)\./i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(–њ—А\.–љ\.–µ\.|–Р–Ф)/i,
  abbreviated: /^(–њ—А\.\s?–•—А\.|–њ–Њ\.\s?–•—А\.)/i,
  wide: /^(–Я—А–µ –•—А–Є—Б—В–∞|–њ—А–µ –љ–Њ–≤–µ –µ—А–µ|–Я–Њ—Б–ї–µ –•—А–Є—Б—В–∞|–љ–Њ–≤–∞ –µ—А–∞)/i,
};
const parseEraPatterns = {
  any: [/^–њ—А/i, /^(–њ–Њ|–љ–Њ–≤–∞)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]\.\s?–Ї–≤\.?/i,
  wide: /^[1234]\. –Ї–≤–∞—А—В–∞–ї/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(10|11|12|[123456789])\./i,
  abbreviated: /^(—Ш–∞–љ|—Д–µ–±|–Љ–∞—А|–∞–њ—А|–Љ–∞—Ш|—Ш—Г–љ|—Ш—Г–ї|–∞–≤–≥|—Б–µ–њ|–Њ–Ї—В|–љ–Њ–≤|–і–µ—Ж)/i,
  wide: /^((—Ш–∞–љ—Г–∞—А|—Ш–∞–љ—Г–∞—А–∞)|(—Д–µ–±—А—Г–∞—А|—Д–µ–±—А—Г–∞—А–∞)|(–Љ–∞—А—В|–Љ–∞—А—В–∞)|(–∞–њ—А–Є–ї|–∞–њ—А–Є–ї–∞)|(–Љ—Ш–∞|–Љ–∞—Ш–∞)|(—Ш—Г–љ|—Ш—Г–љ–∞)|(—Ш—Г–ї|—Ш—Г–ї–∞)|(–∞–≤–≥—Г—Б—В|–∞–≤–≥—Г—Б—В–∞)|(—Б–µ–њ—В–µ–Љ–±–∞—А|—Б–µ–њ—В–µ–Љ–±—А–∞)|(–Њ–Ї—В–Њ–±–∞—А|–Њ–Ї—В–Њ–±—А–∞)|(–љ–Њ–≤–µ–Љ–±–∞—А|–љ–Њ–≤–µ–Љ–±—А–∞)|(–і–µ—Ж–µ–Љ–±–∞—А|–і–µ—Ж–µ–Љ–±—А–∞))/i,
};
const parseMonthPatterns = {
  narrow: [
    /^1/i,
    /^2/i,
    /^3/i,
    /^4/i,
    /^5/i,
    /^6/i,
    /^7/i,
    /^8/i,
    /^9/i,
    /^10/i,
    /^11/i,
    /^12/i,
  ],

  any: [
    /^—Ш–∞/i,
    /^—Д/i,
    /^–Љ–∞—А/i,
    /^–∞–њ/i,
    /^–Љ–∞—Ш/i,
    /^—Ш—Г–љ/i,
    /^—Ш—Г–ї/i,
    /^–∞–≤–≥/i,
    /^—Б/i,
    /^–Њ/i,
    /^–љ/i,
    /^–і/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[–њ—Г—Б—З–љ]/i,
  short: /^(–љ–µ–і|–њ–Њ–љ|—Г—В–Њ|—Б—А–µ|—З–µ—В|–њ–µ—В|—Б—Г–±)/i,
  abbreviated: /^(–љ–µ–і|–њ–Њ–љ|—Г—В–Њ|—Б—А–µ|—З–µ—В|–њ–µ—В|—Б—Г–±)/i,
  wide: /^(–љ–µ–і–µ—Щ–∞|–њ–Њ–љ–µ–і–µ—Щ–∞–Ї|—Г—В–Њ—А–∞–Ї|—Б—А–µ–і–∞|—З–µ—В–≤—А—В–∞–Ї|–њ–µ—В–∞–Ї|—Б—Г–±–Њ—В–∞)/i,
};
const parseDayPatterns = {
  narrow: [/^–њ/i, /^—Г/i, /^—Б/i, /^—З/i, /^–њ/i, /^—Б/i, /^–љ/i],
  any: [/^–љ–µ–і/i, /^–њ–Њ–љ/i, /^—Г—В–Њ/i, /^—Б—А–µ/i, /^—З–µ—В/i, /^–њ–µ—В/i, /^—Б—Г–±/i],
};

const matchDayPeriodPatterns = {
  any: /^(–∞–Љ|–њ–Љ|–њ–Њ–љ–Њ—Ы|(–њ–Њ)?–њ–Њ–і–љ–µ|—Г–≤–µ—З–µ|–љ–Њ—Ы—Г|–њ–Њ—Б–ї–µ –њ–Њ–і–љ–µ|—Г—Ш—Г—В—А—Г)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^a/i,
    pm: /^p/i,
    midnight: /^–њ–Њ–љ–Њ/i,
    noon: /^–њ–Њ–і/i,
    morning: /—Г—Ш—Г—В—А—Г/i,
    afternoon: /(–њ–Њ—Б–ї–µ\s|–њ–Њ)+–њ–Њ–і–љ–µ/i,
    evening: /(—Г–≤–µ—З–µ)/i,
    night: /(–љ–Њ—Ы—Г)/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
